# src/my_package/core.py
"""Core functionality."""""

def hello() -> str:
    """Return a greeting string."""""
    return "Hello from my_package"

def greet(name: str) -> str:
    """Greet a named user."""
    if not isinstance(name, str):
        raise TypeError(f"name must be str, got {type(name).__name__}")
    return f"Hello, {name}!"
